package com.example.logging

import okhttp3.Interceptor
import okhttp3.Response
import okio.Buffer
import java.nio.charset.Charset

class LoggingInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()

        val requestBodyString = request.body?.let { body ->
            val buffer = Buffer()
            body.writeTo(buffer)
            val charset: Charset = body.contentType()?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            buffer.readString(charset)
        }

        AppLogger.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = request.headers.toMultimap().mapValues { it.value.joinToString(",") },
            body = requestBodyString
        )

        val startNs = System.nanoTime()
        return try {
            val response = chain.proceed(request)
            val tookMs = (System.nanoTime() - startNs) / 1_000_000.0
            val responseBodyString = response.peekBody(Long.MAX_VALUE).string()

            AppLogger.logApiResponse(
                method = request.method,
                url = request.url.toString(),
                code = response.code,
                headers = response.headers.toMultimap().mapValues { it.value.joinToString(",") },
                body = responseBodyString
            )
            AppLogger.logDebug("API_CALL completed method=${request.method} url=${request.url} tookMs=${"%.2f".format(tookMs)}")
            response
        } catch (t: Throwable) {
            AppLogger.logException(t, "API_CALL failed method=${request.method} url=${request.url}")
            throw t
        }
    }
}

